function renderStatusIndicator(t,e=null){const r="status-"+t;let n=t.split("-").map(t=>t.charAt(0).toUpperCase()+t.slice(1)).join(" "),i="";switch(t){case"on-time":i="✓";break;case"delayed":i="🕐";break;case"cancelled":i="✕";break;case"boarding":i="✈";break;default:i=""}"delayed"===t&&null!==e&&(n+=" ("+e+" min)");let a='<div class="status-indicator '+r+'" role="status" aria-live="polite">';return a+='<span class="status-icon" aria-hidden="true">'+i+"</span>",a+='<span class="status-text">'+escapeHtml(n)+"</span>",a+="</div>",a}function renderFlightCard(t){if(!t)return console.error("Flight data is null or undefined"),"";const e={id:t.id||"unknown",img:t.img||"img/default.jpg",from:t.from||"N/A",to:t.to||"N/A",fromCity:t.fromCity||"Unknown",toCity:t.toCity||"Unknown",flightNo:t.flightNo||"N/A",airline:t.airline||"Unknown Airline",originTZ:t.originTZ||"UTC",destTZ:t.destTZ||"UTC",departure:t.departure||(new Date).toISOString(),duration:t.duration||0,status:t.status||"on-time",delayMinutes:t.delayMinutes||null};try{const t=formatTimeWithTimezone(e.departure,e.originTZ),r=formatArrivalTime(e.departure,e.duration,e.destTZ),n=formatDuration(e.duration),i=renderStatusIndicator(e.status,e.delayMinutes),a=renderTimezoneDifferenceIndicator(e.departure,e.duration,e.originTZ,e.destTZ),o=renderNextDayIndicator(e.departure,e.duration);let s='<article class="flight-card" role="listitem" aria-label="Flight from '+escapeHtml(e.fromCity)+" to "+escapeHtml(e.toCity)+'">';return s+=`<img data-src="${escapeHtml(e.img)}" alt="${escapeHtml(e.toCity)} destination" class="lazy-image" src="data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 640 400'%3E%3Crect fill='%23e0e0e0' width='640' height='400'/%3E%3C/svg%3E">`,s+='<div class="card-section">',s+=`<h2>${escapeHtml(e.from)} → ${escapeHtml(e.to)}</h2>`,s+=i,s+="<p>",s+=`From ${escapeHtml(e.fromCity)} to ${escapeHtml(e.toCity)}<br>`,s+=`<strong>Flight No. ${escapeHtml(e.flightNo)}</strong><br>`,s+=`${escapeHtml(e.airline)}<br><br>`,s+=`<strong>Departure:</strong> ${t}<br>`,s+=`<strong>Arrival:</strong> ${r} ${o} ${a}<br>`,s+=`<strong>Duration:</strong> ${n}`,s+="</p>",s+="</div>",s+="</article>",s}catch(t){return console.error("Error rendering flight card:",e.id,t),""}}function escapeHtml(t){const e=document.createElement("div");return e.textContent=t,e.innerHTML}function renderLoadingState(){return'\n        <div class="loading-container" role="status" aria-live="polite">\n            <div class="spinner" aria-hidden="true"></div>\n            <p>Loading flight information...</p>\n        </div>\n    '}function renderErrorState(t="Unable to load flight information"){return`\n        <div class="error-container" role="alert">\n            <div class="error-icon" aria-hidden="true">⚠</div>\n            <h3>Error</h3>\n            <p>${t}</p>\n            <button onclick="location.reload()" class="retry-button">\n                Retry\n            </button>\n        </div>\n    `}function renderNoResults(t=""){return`\n        <div class="no-results" role="status">\n            <div class="no-results-icon" aria-hidden="true">🔍</div>\n            <p>${t?`No flights found matching "${escapeHtml(t)}"`:"No flights found"}</p>\n            <p class="no-results-hint">Try searching by destination, airline, or flight number</p>\n            ${t?'<button onclick="clearSearchFromNoResults()" class="btn btn-primary" aria-label="Clear search">Clear Search</button>':""}\n        </div>\n    `}